import boto3
import sys
from botocore.exceptions import ClientError, NoCredentialsError, PartialCredentialsError

BUCKET_NAME = "demo-bucket"

def get_s3_client():
    session = boto3.session.Session()
    return session.client("s3")

def list_all_objects(s3, bucket):
    paginator = s3.get_paginator("list_objects_v2")
    count = 0
    for page in paginator.paginate(Bucket=bucket):
        for obj in page.get("Contents", []):
            key = obj.get("Key", "")
            size = obj.get("Size", 0)
            last_modified = obj.get("LastModified", "")
            print(f"{key}\t{size}\t{last_modified}")
            count += 1
    return count

def main():
    try:
        s3 = get_s3_client()
        total = list_all_objects(s3, BUCKET_NAME)
        if total == 0:
            print("(no objects found)")
    except (NoCredentialsError, PartialCredentialsError):
        print("ERROR: AWS credentials not found. Provide credentials via environment variables, AWS config/credentials files, or an IAM role.")
        sys.exit(2)
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "Unknown")
        msg = e.response.get("Error", {}).get("Message", str(e))
        print(f"ERROR: {code}: {msg}")
        sys.exit(1)

if __name__ == "__main__":
    main()